type Order struct {
	ID       string `json:"id"`
	Customer string `json:"customer"`
	Items    []Item `json:"items"`
}

type Item struct {
	ID     string `json:"id"`
	Name   string `json:"name"`
	Qty    int    `json:"qty"`
	Price  float64 `json:"price"`
	SubTotal float64 `json:"sub_total"`
}

func orderHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		vars := mux.Vars(r)
		orderID := vars["id"]

		query := `
			SELECT customer, items.id, items.name, items.qty, items.price
			FROM orders
			INNER JOIN items ON orders.id = $1 AND orders.items_id = items.id
		`
		row := db.QueryRowContext(context.Background(), query, orderID)

		var o Order

		err := row.Scan(&o.Customer, &o.Items)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}

		json.NewEncoder(w).Encode(o)
	}
}

